576: function Write-JsonFile {
577:     param(
578:         [Parameter(Mandatory)] [string] $Path,
579:         [Parameter(Mandatory)] $Value
580:     )
581: 
582:     $json = $Value | ConvertTo-Json -Depth 30
583:     [IO.File]::WriteAllText($Path, $json + "`n", [Text.UTF8Encoding]::new($false))
584: }
585: 
586: function Assert-ByteIdentical {
587:     param(
588:         [Parameter(Mandatory)] [string] $Candidate,
589:         [Parameter(Mandatory)] [string] $Committed,
590:         [Parameter(Mandatory)] [string] $Name
591:     )
592: 
593:     if (-not (Test-Path -LiteralPath $Committed -PathType Leaf)) {
594:         throw "committed $Name evidence is missing: $Committed"
595:     }
596:     $actual = [IO.File]::ReadAllBytes($Candidate)
597:     $expected = [IO.File]::ReadAllBytes($Committed)
598:     if ($actual.Length -ne $expected.Length) {
599:         throw "$Name evidence differs from the committed input-bound golden; review and run with -UpdateEvidence"
600:     }
601:     for ($index = 0; $index -lt $actual.Length; $index++) {
602:         if ($actual[$index] -ne $expected[$index]) {
603:             throw "$Name evidence differs from the committed input-bound golden; review and run with -UpdateEvidence"
604:         }
605:     }
606: }
607: 
608: function Move-Replace {
