627: function Read-CurrentGeneration {
628:     param([Parameter(Mandatory)] [string] $RepoRoot)
629: 
630:     $pointerPath = Get-CurrentGenerationPointerPath -RepoRoot $RepoRoot
631:     if (-not (Test-Path -LiteralPath $pointerPath -PathType Leaf)) {
632:         throw 'current-generation pointer is missing'
633:     }
634:     $pointer = Get-Content -Raw -LiteralPath $pointerPath | ConvertFrom-Json
635:     if (-not $pointer.generation_id) { throw 'current-generation pointer lacks generation_id' }
636:     $genDir = Join-Path (Get-EvidenceGenerationRoot -RepoRoot $RepoRoot) $pointer.generation_id
637:     $structural = Join-Path $genDir 'structural-report-v1.json'
638:     $conformance = Join-Path $genDir 'conformance-report-v1.json'
639:     if (-not (Test-Path -LiteralPath $structural -PathType Leaf) -or -not (Test-Path -LiteralPath $conformance -PathType Leaf)) {
640:         throw "current generation $($pointer.generation_id) is incomplete"
641:     }
642:     $structuralHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $structural).Hash.ToLowerInvariant()
643:     $conformanceHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $conformance).Hash.ToLowerInvariant()
644:     if ($pointer.structural_sha256 -ne $structuralHash -or $pointer.conformance_sha256 -ne $conformanceHash) {
645:         throw "current generation $($pointer.generation_id) hashes do not match generation files"
646:     }
647:     return [ordered]@{
648:         generation_id = $pointer.generation_id
649:         structural_path = $structural
650:         conformance_path = $conformance
651:         structural_sha256 = $structuralHash
652:         conformance_sha256 = $conformanceHash
653:         pointer_path = $pointerPath
654:     }
655: }
