657: function Publish-EvidencePair {
658:     param(
659:         [Parameter(Mandatory)] [string] $StructuralCandidate,
660:         [Parameter(Mandatory)] [string] $ConformanceCandidate,
661:         [Parameter(Mandatory)] [string] $RepoRoot
662:     )
663: 
664:     # Stage an immutable generation on the destination volume, verify the pair,
665:     # then publish the small current-generation pointer last.
666:     $generationRoot = Get-EvidenceGenerationRoot -RepoRoot $RepoRoot
667:     if (-not (Test-Path -LiteralPath $generationRoot)) {
668:         New-Item -ItemType Directory -Force -Path $generationRoot | Out-Null
669:     }
670:     $generationId = [guid]::NewGuid().ToString('N')
671:     $stageDir = Join-Path $generationRoot $generationId
672:     New-Item -ItemType Directory -Force -Path $stageDir | Out-Null
673: 
674:     $stagedStructural = Join-Path $stageDir 'structural-report-v1.json'
675:     $stagedConformance = Join-Path $stageDir 'conformance-report-v1.json'
676:     $stagedPointer = Join-Path $stageDir 'generation-manifest.json'
677: 
678:     try {
679:         [IO.File]::Copy($StructuralCandidate, $stagedStructural, $true)
680:         [IO.File]::Copy($ConformanceCandidate, $stagedConformance, $true)
681:         $structuralHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $stagedStructural).Hash.ToLowerInvariant()
682:         $conformanceHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $stagedConformance).Hash.ToLowerInvariant()
683:         $manifest = [ordered]@{
684:             schema_version = 1
685:             generation_id = $generationId
686:             structural_sha256 = $structuralHash
687:             conformance_sha256 = $conformanceHash
688:             structural_file = 'structural-report-v1.json'
689:             conformance_file = 'conformance-report-v1.json'
690:             report_roles = [ordered]@{
691:                 structural = 'payload'
692:                 conformance = 'envelope'
693:             }
694:             published_at_utc = (Get-Date).ToUniversalTime().ToString('o')
695:         }
696:         Write-JsonFile -Path $stagedPointer -Value $manifest
697: 
698:         # Verify full pair before pointer publication.
699:         Assert-ByteIdentical -Candidate $stagedStructural -Committed $StructuralCandidate -Name 'staged-structural'
700:         Assert-ByteIdentical -Candidate $stagedConformance -Committed $ConformanceCandidate -Name 'staged-conformance'
701:         if ($structuralHash.Length -ne 64 -or $conformanceHash.Length -ne 64) {
702:             throw 'staged generation produced invalid hashes'
703:         }
704: 
705:         # Mirror convenience copies for stable paths (byte-identical to generation).
706:         $mirrorStructural = Join-Path $RepoRoot 'reference\evidence\structural-report-v1.json'
707:         $mirrorConformance = Join-Path $RepoRoot 'reference\evidence\conformance-report-v1.json'
708:         [IO.File]::Copy($stagedStructural, $mirrorStructural, $true)
709:         [IO.File]::Copy($stagedConformance, $mirrorConformance, $true)
710: 
711:         $pointerPath = Get-CurrentGenerationPointerPath -RepoRoot $RepoRoot
712:         $pointer = [ordered]@{
713:             schema_version = 1
714:             generation_id = $generationId
715:             structural_sha256 = $structuralHash
716:             conformance_sha256 = $conformanceHash
717:             structural_relative_path = "generations/$generationId/structural-report-v1.json"
718:             conformance_relative_path = "generations/$generationId/conformance-report-v1.json"
719:         }
720:         $pointerTemp = Join-Path $stageDir 'current-generation.pointer.tmp'
721:         Write-JsonFile -Path $pointerTemp -Value $pointer
722:         Move-Replace -Source $pointerTemp -Destination $pointerPath
723:     } catch {
724:         if (Test-Path -LiteralPath $stageDir) {
725:             Remove-Item -LiteralPath $stageDir -Recurse -Force -ErrorAction SilentlyContinue
726:         }
727:         throw
728:     }
729: }
