767: function ConvertTo-EvidencePath {
768:     param(
769:         [Parameter(Mandatory)] [string] $Path,
770:         [Parameter(Mandatory)] [string] $RepoRoot,
771:         [string] $RunRoot = $null
772:     )
773: 
774:     $full = [IO.Path]::GetFullPath($Path)
775:     $repo = [IO.Path]::GetFullPath($RepoRoot).TrimEnd('\', '/')
776:     if ($RunRoot) {
777:         $run = [IO.Path]::GetFullPath($RunRoot).TrimEnd('\', '/')
778:         if ($full.StartsWith($run + [IO.Path]::DirectorySeparatorChar, [StringComparison]::OrdinalIgnoreCase) -or
779:             $full.Equals($run, [StringComparison]::OrdinalIgnoreCase)) {
780:             $suffix = if ($full.Length -gt $run.Length) { $full.Substring($run.Length).TrimStart('\', '/') } else { '' }
781:             if ($suffix) { return '${RUN_TEMP}/' + ($suffix -replace '\\', '/') }
782:             return '${RUN_TEMP}'
783:         }
784:     }
785:     if ($full.StartsWith($repo + [IO.Path]::DirectorySeparatorChar, [StringComparison]::OrdinalIgnoreCase) -or
786:         $full.Equals($repo, [StringComparison]::OrdinalIgnoreCase)) {
787:         $suffix = if ($full.Length -gt $repo.Length) { $full.Substring($repo.Length).TrimStart('\', '/') } else { '' }
788:         if ($suffix) { return '${REPO}/' + ($suffix -replace '\\', '/') }
789:         return '${REPO}'
790:     }
791:     # Keep tool identity, not host-absolute install paths.
792:     return [IO.Path]::GetFileName($full)
793: }
