795: function ConvertTo-OrderedOfflineEnvironment {
796:     param([hashtable] $OfflineEnvironment)
797: 
798:     $ordered = [ordered]@{}
799:     foreach ($key in @($OfflineEnvironment.Keys | Sort-Object -CaseSensitive)) {
800:         $ordered[$key] = [string]$OfflineEnvironment[$key]
801:     }
802:     return $ordered
803: }
