805: function New-CommandRecord {
806:     param(
807:         [Parameter(Mandatory)] [string] $LogicalTool,
808:         [Parameter(Mandatory)] [string] $Executable,
809:         [Parameter(Mandatory)] [string] $Cwd,
810:         [Parameter(Mandatory)] [string[]] $Argv,
811:         [string] $PinnedVersion = '',
812:         [hashtable] $OfflineEnvironment = @{},
813:         [string] $InlineSourceSha256 = $null,
814:         [int] $ExitCode = 0,
815:         [string] $RepoRoot = $null,
816:         [string] $RunRoot = $null
