105: func TestRejectsEveryWrongLengthAndTrailingByte(t *testing.T) {
106: 	tests := []struct {
107: 		name      string
108: 		proof, vk []byte
109: 		pub       []byte
110: 		expected  error
111: 	}{
112: 		{"proof-short", make([]byte, ProofLength-1), make([]byte, VKLength), make([]byte, PublicScalarLength), ErrProofLength},
113: 		{"proof-trailing", make([]byte, ProofLength+1), make([]byte, VKLength), make([]byte, PublicScalarLength), ErrProofLength},
114: 		{"vk-short", make([]byte, ProofLength), make([]byte, VKLength-1), make([]byte, PublicScalarLength), ErrVKLength},
115: 		{"vk-trailing", make([]byte, ProofLength), make([]byte, VKLength+1), make([]byte, PublicScalarLength), ErrVKLength},
116: 		{"scalar-short", make([]byte, ProofLength), make([]byte, VKLength), make([]byte, PublicScalarLength-1), ErrPublicScalarLength},
117: 		{"scalar-trailing", make([]byte, ProofLength), make([]byte, VKLength), make([]byte, PublicScalarLength+1), ErrPublicScalarLength},
118: 	}
119: 	for _, test := range tests {
120: 		t.Run(test.name, func(t *testing.T) {
121: 			if _, err := Parse(test.proof, test.vk, test.pub); !errors.Is(err, test.expected) {
122: 				t.Fatalf("expected %v, got %v", test.expected, err)
123: 			}
124: 		})
125: 	}
126: }
