128: func TestEveryRegisteredFieldHasExactCompleteSliceAndMetadata(t *testing.T) {
129: 	proof := make([]byte, ProofLength)
130: 	vk := make([]byte, VKLength)
131: 	for index := range proof {
132: 		proof[index] = byte((index*17 + 3) % 251)
133: 	}
134: 	for index := range vk {
135: 		vk[index] = byte((index*29 + 11) % 251)
136: 	}
137: 	parsed, err := Parse(proof, vk, make([]byte, PublicScalarLength))
138: 	if err != nil {
139: 		t.Fatal(err)
140: 	}
141: 	proofFields := map[string][]byte{
142: 		"A": parsed.Proof.A, "B": parsed.Proof.B, "C": parsed.Proof.C,
143: 		"D": parsed.Proof.D, "PoK": parsed.Proof.PoK,
144: 	}
145: 	vkFields := map[string][]byte{
146: 		"alpha": parsed.VK.Alpha, "beta": parsed.VK.Beta, "gamma": parsed.VK.Gamma,
147: 		"delta": parsed.VK.Delta, "IC0": parsed.VK.IC0, "IC1": parsed.VK.IC1,
148: 		"K2": parsed.VK.K2, "CK.G": parsed.VK.CKG, "CK.GSigmaNeg": parsed.VK.CKGSigmaNeg,
149: 	}
150: 	assertLayout := func(t *testing.T, source []byte, fields map[string][]byte, actual, expected []FieldLayout) {
151: 		t.Helper()
152: 		if len(actual) != len(expected) {
153: 			t.Fatalf("layout has %d fields, want %d", len(actual), len(expected))
154: 		}
155: 		for index, want := range expected {
156: 			if actual[index] != want {
157: 				t.Fatalf("layout[%d] = %+v, want %+v", index, actual[index], want)
158: 			}
159: 			if !bytes.Equal(fields[want.Name], source[want.Offset:want.Offset+want.Length]) {
160: 				t.Fatalf("field %s does not equal complete registered slice", want.Name)
161: 			}
162: 		}
163: 	}
164: 	assertLayout(t, proof, proofFields, parsed.ProofLayout, []FieldLayout{
165: 		{"A", 0, 48}, {"B", 48, 96}, {"C", 144, 48}, {"D", 192, 96}, {"PoK", 288, 48},
166: 	})
167: 	assertLayout(t, vk, vkFields, parsed.VKLayout, []FieldLayout{
168: 		{"alpha", 0, 48}, {"beta", 48, 96}, {"gamma", 144, 96},
169: 		{"delta", 240, 96}, {"IC0", 336, 48}, {"IC1", 384, 48},
170: 		{"K2", 432, 48}, {"CK.G", 480, 96}, {"CK.GSigmaNeg", 576, 96},
171: 	})
172: 	if parsed.CryptographicVerification {
173: 		t.Fatal("parser must not claim cryptographic verification")
174: 	}
175: 	if parsed.FullDeciderGate != "unresolved" || parsed.CardanoExecutionGate != "unresolved" {
176: 		t.Fatalf("parser closed a proof gate: %+v", parsed)
177: 	}
178: }
